<Stats id="monster-ohancanu--stats" atts={[23,14,19,7,14,8]} bab={3} cmb={10} cmd={22} feats={["Improved Initiative","Intimidating Prowess","Power Attack",["Weapon Focus"," (greataxe)"]]} skills={{"climb":{"b":16}}} lang={["Ak","C","S"]} />
