<Stats id="monster-orc_gorthek--stats" atts={[32,9,21,2,10,5]} bab={6} cmb={18} cmbP="+20 bull rush or sunder" cmd={27} cmdP="29 vs. bull rush or sunder, 31 vs. trip" feats={["Awesome Blow","Great Fortitude","Improved Bull Rush","Improved Sunder","Power Attack"]} skills={{"per":{"b":12}}} />
