<Stats id="monster-orc_orc_mystic--stats" atts={[17,8,12,8,13,12]} bab={2} cmb={5} cmd={14} feats={["Combat Casting",["Skill Focus"," (Stealth)"]]} skills={{"k":{"r":4},"per":{"b":2},"stl":{"b":4}}} lang={["C","O"]} sq="weapon familiarity" combat={[["Ssound burst"],["Ssummon monster II"]]} othergear={[["Abp"],["Wba"],["4","Wjs"],["WIclk1"],["Qwooden holy symbol"],"135 gp"]} />
